  <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">Cambia el Valor Predeterminado, Cambia el Resultado</text>
  <text x="20" y="42" fill="#71717a" font-size="10" font-family="sans-serif">Basado en cifras de Madrian &amp; Shea (2001), Johnson &amp; Goldstein (2003)</text>
  <rect x="470" y="16" width="10" height="10" fill="#71717a"/><text x="484" y="25" fill="#a1a1aa" font-size="10" font-family="sans-serif">Antes del predeterminado</text>
  <rect x="470" y="32" width="10" height="10" fill="#4ade80"/><text x="484" y="41" fill="#a1a1aa" font-size="10" font-family="sans-serif">Después del predeterminado</text>
  <line x1="90" y1="250" x2="610" y2="250" stroke="rgba(255,255,255,.15)"/>
  <rect x="130" y="180" width="36" height="70" fill="#71717a" rx="3"/>
  <text x="148" y="172" fill="#d4d4d8" font-size="12" text-anchor="middle" font-family="sans-serif">37%</text>
