<div class="es">
<svg viewBox="0 0 700 420" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">La Prueba de Recompra — Cuatro Cuadrantes</text>
  <text x="20" y="42" fill="#71717a" font-size="10" font-family="sans-serif">Posee o no × compraría hoy o no</text>
  <text x="235" y="52" fill="#a1a1aa" font-size="11" text-anchor="middle" font-family="sans-serif">No compraría hoy</text>
  <text x="465" y="52" fill="#a1a1aa" font-size="11" text-anchor="middle" font-family="sans-serif">Compraría hoy</text>
  <text x="103" y="144" fill="#a1a1aa" font-size="11" text-anchor="end" font-family="sans-serif">Posee</text>
  <text x="103" y="304" fill="#a1a1aa" font-size="11" text-anchor="end" font-family="sans-serif">No posee</text>
  <rect x="120" y="60" width="230" height="160" fill="rgba(248,113,113,0.12)" stroke="rgba(248,113,113,0.35)" rx="6"/>
  <rect x="350" y="60" width="230" height="160" fill="rgba(74,222,128,0.12)" stroke="rgba(74,222,128,0.35)" rx="6"/>
  <rect x="120" y="220" width="230" height="160" fill="rgba(161,161,170,0.10)" stroke="rgba(161,161,170,0.30)" rx="6"/>
  <rect x="350" y="220" width="230" height="160" fill="rgba(251,191,36,0.12)" stroke="rgba(251,191,36,0.35)" rx="6"/>
  <text x="235" y="130" fill="#fca5a5" font-size="14" font-weight="700" text-anchor="middle" font-family="sans-serif">Trampa del Status Quo</text>
